"use client";

import Link from "next/link";
import { useMemo, useState } from "react";

type AmbassadorSubpageMode = "create" | "profile" | "edit" | "delete" | "recruitment" | "onboarding" | "missions" | "programs" | "rewards" | "territories" | "approvals" | "compliance" | "analytics" | "assets";

type WorkflowItem = {
  id: string;
  title: string;
  status: "open" | "active" | "review" | "approved" | "blocked" | "closed";
  owner: string;
  priority: "critical" | "high" | "medium" | "low";
  score: number;
  note: string;
};

const modeConfig: Record<AmbassadorSubpageMode, { eyebrow: string; title: string; subtitle: string; primary: string; secondary: string }> = {
  create: { eyebrow: "Candidate intake", title: "Create Ambassador Profile", subtitle: "Qualify a new ambassador with trust, audience, territory, channel, compliance, and program fit before activation.", primary: "Save candidate", secondary: "Send screening checklist" },
  profile: { eyebrow: "Command room", title: "Ambassador Profile Command Room", subtitle: "Control one ambassador profile, missions, proof, rewards, risk, and performance history.", primary: "Update profile", secondary: "Assign mission" },
  edit: { eyebrow: "Profile editing", title: "Edit Ambassador Operating Profile", subtitle: "Adjust ownership, tier, channel permissions, territory, program access, payout rules, and brand guardrails.", primary: "Save changes", secondary: "Request approval" },
  delete: { eyebrow: "Safe removal", title: "Remove or Archive Ambassador", subtitle: "Protect history while removing access, stopping missions, freezing rewards, and preserving audit logs.", primary: "Archive safely", secondary: "Freeze active work" },
  recruitment: { eyebrow: "Recruitment pipeline", title: "Ambassador Recruitment Control", subtitle: "Source, screen, qualify, approve, and reject candidates based on trust, reach, credibility, and territory needs.", primary: "Approve candidate", secondary: "Reject candidate" },
  onboarding: { eyebrow: "Activation command", title: "Onboarding and Training Workspace", subtitle: "Move approved ambassadors through training, brand rules, disclosure rules, proof quality, and first mission readiness.", primary: "Mark onboarded", secondary: "Send training pack" },
  missions: { eyebrow: "Execution layer", title: "Mission Control and Proof Validation", subtitle: "Assign missions, validate proof, reject weak submissions, release rewards, and protect brand quality.", primary: "Assign mission", secondary: "Validate proof" },
  programs: { eyebrow: "Program configuration", title: "Affiliate Program Builder", subtitle: "Design ambassador programs, referral rules, reward models, mission templates, and territory-specific activation flows.", primary: "Save program", secondary: "Duplicate template" },
  rewards: { eyebrow: "Finance control", title: "Rewards, Commissions, and Payouts", subtitle: "Control reward exposure, payout eligibility, bonus logic, deductions, freezes, and validation status.", primary: "Approve payout", secondary: "Freeze payout" },
  territories: { eyebrow: "Geographic command", title: "Territory and City Cell Control", subtitle: "Manage city coverage, local owners, ambassador density, territory conflicts, and expansion readiness.", primary: "Open territory", secondary: "Reassign owner" },
  approvals: { eyebrow: "Approval desk", title: "Ambassador Approval and Review Desk", subtitle: "Approve candidates, missions, proof, sensitive brand content, payment release, and territory expansion requests.", primary: "Approve selected", secondary: "Escalate to manager" },
  compliance: { eyebrow: "Risk protection", title: "Compliance and Brand Safety Center", subtitle: "Enforce disclosure, consent, brand tone, no unsupported claims, quality gates, and risk intervention playbooks.", primary: "Resolve case", secondary: "Open intervention" },
  analytics: { eyebrow: "Performance intelligence", title: "Ambassador Analytics and Growth Intelligence", subtitle: "Analyze leads, conversion, revenue, reward ROI, risk, activity, and program-level growth signals.", primary: "Export snapshot", secondary: "Create insight" },
  assets: { eyebrow: "Enablement bank", title: "Ambassador Asset Packs and Brand Kits", subtitle: "Distribute approved scripts, posts, proof templates, disclosure examples, city packs, and campaign kits.", primary: "Publish asset pack", secondary: "Request creative" },
};

const seedItems: WorkflowItem[] = [
  { id: "wf-001", title: "Validate Rabat elite mission proof", status: "review", owner: "Ambassador Ops", priority: "critical", score: 92, note: "High revenue impact; proof quality appears strong." },
  { id: "wf-002", title: "Screen Casablanca corporate mother candidate", status: "active", owner: "Community Manager", priority: "high", score: 78, note: "Good audience fit, needs disclosure training." },
  { id: "wf-003", title: "Freeze Fes academy payout until correction", status: "blocked", owner: "Compliance", priority: "critical", score: 43, note: "Disclosure issue requires intervention before payout." },
  { id: "wf-004", title: "Prepare Marrakech city launch pack", status: "open", owner: "Brand Manager", priority: "medium", score: 67, note: "Needs localized proof examples and hotel referral messaging." },
  { id: "wf-005", title: "Approve clinic referral sprint expansion", status: "approved", owner: "Growth Lead", priority: "high", score: 88, note: "Ready to scale with partner consent controls." },
];

function cx(...items: Array<string | false | undefined>) { return items.filter(Boolean).join(" "); }
function pct(n: number) { return `${Math.max(0, Math.min(100, n))}%`; }

export default function AmbassadorExecutiveSubpage({ mode, id }: { mode: AmbassadorSubpageMode; id?: string }) {
  const config = modeConfig[mode];
  const [items, setItems] = useState(seedItems);
  const [query, setQuery] = useState("");
  const [selected, setSelected] = useState(seedItems[0]?.id || "");
  const [note, setNote] = useState("Senior operator note: keep growth aggressive, but never sacrifice compliance, proof quality, or brand trust.");
  const filtered = useMemo(() => items.filter(item => `${item.title} ${item.owner} ${item.status} ${item.priority} ${item.note}`.toLowerCase().includes(query.toLowerCase())), [items, query]);
  const activeItem = items.find(item => item.id === selected) || items[0];
  function setStatus(itemId: string, status: WorkflowItem["status"]) { setItems(list => list.map(item => item.id === itemId ? { ...item, status } : item)); }
  function addItem() { const id = `wf-${Date.now()}`; setItems(list => [{ id, title: `New ${mode} operation`, status: "open", owner: "Ambassador Ops", priority: "medium", score: 50, note: "New operation created from executive workspace." }, ...list]); setSelected(id); }
  function removeSelected() { setItems(list => list.filter(item => item.id !== selected)); setSelected(items[0]?.id || ""); }

  return <main data-market-os-root className="amb-subpage">
    <section className="amb-sub-hero"><div><Link href="/market-os/ambassadors">← Ambassador command center</Link><span>{config.eyebrow}</span><h1>{config.title}</h1><p>{config.subtitle}</p><div className="amb-sub-actions"><button onClick={addItem}>{config.primary}</button><button>{config.secondary}</button><button onClick={removeSelected}>Remove selected</button><Link href="/market-os/ambassadors/create">Create new</Link></div></div><aside><b>Current object</b><strong>{id || mode}</strong><textarea value={note} onChange={e => setNote(e.target.value)} /></aside></section>
    <section className="amb-sub-controls"><input value={query} onChange={e => setQuery(e.target.value)} placeholder="Search this workspace..." /><button onClick={() => setItems(list => list.map(item => ({ ...item, score: Math.min(100, item.score + 5) })))}>Boost scores</button><button onClick={() => setItems(list => list.map(item => item.priority === "critical" ? { ...item, status: "review" } : item))}>Move critical to review</button><button onClick={() => setItems(list => list.map(item => item.status === "blocked" ? { ...item, owner: "Compliance" } : item))}>Assign blockers</button></section>
    <section className="amb-sub-grid"><aside className="amb-sub-left"><h2>Workspace tools</h2>{["Create", "Edit", "Delete", "Approve", "Reject", "Assign", "Validate", "Freeze", "Export", "Escalate", "Duplicate", "Archive"].map(tool => <button key={tool}>{tool}</button>)}</aside><section className="amb-sub-board"><div className="amb-sub-board-head"><h2>{modeConfig[mode].title}</h2><b>{filtered.length} operations</b></div>{filtered.map(item => <article key={item.id} className={cx("amb-work-item", selected === item.id && "selected", item.status)} onClick={() => setSelected(item.id)}><div><span>{item.priority}</span><strong>{item.title}</strong><p>{item.note}</p></div><div className="amb-progress"><i style={{ width: pct(item.score) }} /></div><div className="amb-work-actions"><button onClick={(e) => { e.stopPropagation(); setStatus(item.id, "active"); }}>Active</button><button onClick={(e) => { e.stopPropagation(); setStatus(item.id, "review"); }}>Review</button><button onClick={(e) => { e.stopPropagation(); setStatus(item.id, "approved"); }}>Approve</button><button onClick={(e) => { e.stopPropagation(); setStatus(item.id, "blocked"); }}>Block</button></div><b>{item.status}</b></article>)}</section><aside className="amb-sub-right"><h2>Selected detail</h2>{activeItem && <><strong>{activeItem.title}</strong><p>{activeItem.note}</p><ul><li>Owner: {activeItem.owner}</li><li>Priority: {activeItem.priority}</li><li>Status: {activeItem.status}</li><li>Score: {activeItem.score}</li></ul></>}<div className="amb-ai-box"><span>AI Agent Assistant</span><p>Recommended action: validate proof quality first, then release execution or payout only after compliance gates pass.</p><button>Create AI task</button></div></aside></section>
    <section className="amb-sub-panels">{["Executive summary", "Operational risk", "Reward exposure", "Territory pressure", "Brand safety", "Proof quality", "Program ROI", "Next best actions"].map((panel, index) => <article key={panel}><b>{String(index + 1).padStart(2, "0")}</b><h3>{panel}</h3><p>This panel gives the senior ambassador program operator direct control over {panel.toLowerCase()} with actions, filters, and decision support.</p><button>Open {panel}</button></article>)}</section>
    <style jsx>{`.amb-subpage{min-height:100vh;background:#07111f;color:#eef6ff;padding:28px;display:grid;gap:22px;font-family:Inter,system-ui}.amb-sub-hero{display:grid;grid-template-columns:1.4fr .7fr;gap:20px;background:linear-gradient(135deg,#0d1c34,#07111f);border:1px solid #ffffff16;border-radius:32px;padding:28px}.amb-sub-hero a,.amb-sub-actions a{color:white;text-decoration:none}.amb-sub-hero span{color:#7dd3fc;text-transform:uppercase;letter-spacing:.14em;font-size:12px;font-weight:900}.amb-sub-hero h1{font-size:44px;margin:10px 0}.amb-sub-hero p{color:#b9c7d8;line-height:1.7}.amb-sub-hero aside,.amb-sub-left,.amb-sub-board,.amb-sub-right,.amb-sub-panels,.amb-sub-controls{background:#0b1729;border:1px solid #ffffff14;border-radius:26px;padding:18px}.amb-sub-hero textarea{width:100%;min-height:120px;background:#06101d;border:1px solid #ffffff22;color:white;border-radius:16px;padding:12px}.amb-sub-actions,.amb-sub-controls,.amb-work-actions{display:flex;flex-wrap:wrap;gap:10px}.amb-sub-actions button,.amb-sub-actions a,.amb-sub-controls button,.amb-sub-left button,.amb-work-actions button,.amb-ai-box button,.amb-sub-panels button{background:#ffffff10;border:1px solid #ffffff20;color:white;border-radius:13px;padding:10px 12px;font-weight:800;cursor:pointer}.amb-sub-actions button:first-child{background:#38bdf8;color:#06111f}.amb-sub-controls input{flex:1;min-width:260px;background:#06101d;color:white;border:1px solid #ffffff22;border-radius:14px;padding:12px}.amb-sub-grid{display:grid;grid-template-columns:240px 1fr 320px;gap:16px}.amb-sub-left{display:grid;gap:10px;height:max-content}.amb-sub-board{display:grid;gap:12px}.amb-sub-board-head{display:flex;justify-content:space-between}.amb-work-item{position:relative;display:grid;gap:12px;background:#07111f;border:1px solid #ffffff14;border-radius:22px;padding:16px;cursor:pointer}.amb-work-item.selected{outline:2px solid #38bdf8}.amb-work-item.blocked{border-color:#fb718555}.amb-work-item span{color:#7dd3fc;text-transform:uppercase;font-size:11px;font-weight:900}.amb-work-item strong{font-size:20px}.amb-work-item p{color:#b9c7d8}.amb-progress{height:8px;background:#ffffff12;border-radius:999px;overflow:hidden}.amb-progress i{display:block;height:100%;background:#38bdf8}.amb-work-item>b{position:absolute;right:14px;top:14px;background:#ffffff12;border-radius:999px;padding:7px 10px}.amb-sub-right strong{font-size:22px}.amb-sub-right li{margin:8px 0;color:#b9c7d8}.amb-ai-box{margin-top:16px;background:#07111f;border:1px solid #ffffff14;border-radius:20px;padding:16px}.amb-ai-box span{color:#7dd3fc;text-transform:uppercase;font-size:12px;font-weight:900}.amb-sub-panels{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.amb-sub-panels article{background:#07111f;border:1px solid #ffffff14;border-radius:20px;padding:16px}@media(max-width:1100px){.amb-sub-hero,.amb-sub-grid,.amb-sub-panels{grid-template-columns:1fr}}`}</style>
  </main>;
}

